    Log log = new Log("log/surveyCake.log").setIfDisplayTime(true);

    try{
        String apname = request.getParameter("a");
        String svid = request.getParameter("svid");
        String hash = request.getParameter("hash");
        String path = request.getParameter("p");
        String domain = request.getParameter("domain");

        if(!path.contains("/")){
            path = "/" + path;
        }
        String sheetIndex = request.getParameter("si");

        if (null == svid || hash == null) {
            return;
        }

        //#1. 透過svid與hash取得加密字串
        String version = "v0";
        String realDomain = getRealDomain(domain);
        String queryUrl = String.format("https://%s/webhook/%s/%s/%s", realDomain, version, svid, hash);

        String encryptStr = URLCaller.getString(queryUrl);

        if (Encoder.isEmptyOrWhitespaceOnly(encryptStr)) {
            return;
        }

        Account account = Account.getInstance(apname);
        account.resetConstants(); //去ragic-setup撈資料

        //#2. 檢核全域常數是否有設定ivkey, hashkey
        //surveyCake全域常數hashkey名稱, 格式為surveycake_{path}_{sheetIndex}_hashkey
        String formatPrefix = "c_surveycake_%s_%s_";
        String noSlashPath = path.replace("/", "");

        CustomConstant constHashKey = account
                .getCustomConstant(String.format(formatPrefix + "hashkey", noSlashPath, sheetIndex));
        if(constHashKey == null || Encoder.isEmptyOrWhitespaceOnly(constHashKey.getValue())){
            return;
        }

        //surveyCake全域常數ivykey名稱, 格式為surveycake_{path}_{sheetIndex}_ivykey
        CustomConstant constIvKey = account
                .getCustomConstant(String.format(formatPrefix + "ivkey", noSlashPath, sheetIndex));
        if(constIvKey == null || Encoder.isEmptyOrWhitespaceOnly(constIvKey.getValue())){
            return;
        }

        //#3 透過hashKey, ivkey解密encrypt的資料
        String ivKey = constIvKey.getValue();
        String hashKey = constHashKey.getValue();
        String decryptStr = getDecryptString(encryptStr, hashKey, ivKey);
        if (decryptStr == null) {
            //可能是加密字串有誤, domain有問題..
            if(!Encoder.isEmptyOrWhitespaceOnly(domain)){
                log.info(String.format("domain: %s, svid: %s, hash: %s, ivKey: %s, hashKey: %s", domain, svid, hash, ivKey, hashKey));
            }else{
                log.info(String.format("svid: %s, hash: %s, ivKey: %s, hashKey: %s", svid, hash, ivKey, hashKey));
            }
            return;
        }

        JSONObject tryBeginObj = new JSONObject(decryptStr);
        SurveyCakeTryBegin surveyCake = new SurveyCakeTryBegin();
        Map<Integer, String> res = surveyCake.getTryBeginSheetData(tryBeginObj);
        User user = (User) session.getAttribute("USER");
        RagicBundle bundle = (RagicBundle) session.getAttribute("RAGIC_BUNDLE");

        APIQuery aq = new APIQuery(apname, path, sheetIndex);
        aq.setUpdateMode();

        APIResultsFull result = aq.getAPIResultsFull();
        boolean updateFlag = false;

        //如果沒有pk則視為新增
        if(!hasPrimaryKey(surveyCake)) {
            APIEntry e = aq.insertAPIEntry();

            updateEntryData(e, res);

            //存檔前要讀取欄位相關設定公式, 連結載入, 預設值...
            loadAllResource(e, user, bundle);
            e.save(user, bundle);
        }else{
            //若有pk則判斷該pk有沒有出現在表單上來決定更新或新增
            for (APIEntry e : result) {
                String ragicKey = e.getFieldValue(surveyCake.getKeyAlias());
                if (surveyCake.getKeyValue().equals(ragicKey)) {

                    //important 注意updateEntryData, loadAllResource順序不可調換
                    updateEntryData(e, res);

                    //存檔前要讀取欄位相關設定公式, 連結載入, 預設值...
                    loadAllResource(e, user, bundle);
                    e.save(user, bundle);

                    updateFlag = true;
                    break;
                }
            }

            if (!updateFlag) {
                APIEntry e = aq.insertAPIEntry();
                updateEntryData(e, res);

                //存檔前要讀取欄位相關設定公式, 連結載入, 預設值...
                loadAllResource(e, user, bundle);
                e.save(user, bundle);
            }
        }
    }catch(Exception e){
        log.info(e.getMessage());
    }


      out.write("<script>opener.silentReload();\r\nwindow.close();</script>\r\n");
